import React, { useState, useEffect, useRef, useMemo } from 'react';
import { 
  Send, QrCode, Users, History, Settings, Coins, LogOut, CheckCircle2, 
  AlertCircle, Smartphone, ShieldCheck, LayoutDashboard, ArrowRight, 
  UploadCloud, User, Loader2, Lock, ChevronRight, PlusCircle, CreditCard, 
  Zap, ShoppingBag, Ticket, Image as ImageIcon, Film, X, Database, 
  Activity, Search, Edit, Trash2, MoreVertical, Save, ShieldAlert, 
  TrendingUp, MessageSquare, Server, Plus, Minus, Bell, LogIn, Play, Download,
  RefreshCw, ListPlus, Paperclip, XCircle, Gift, Calendar, Crown, Star, KeyRound,
  Mail, Building2
} from 'lucide-react';

const API_URL = 'http://localhost:5000/api';

/* ============================================================================
   KONSTANTA & HARGA PAKET
   ============================================================================ */
// Paket Berlangganan Bulanan
const SUBSCRIPTION_PACKAGES = [
  { id: 'sub_1', name: 'Paket Dasar', price: 49, credits: 2000, features: ['2.000 Kredit per bulan', 'Dukungan Dasar', 'Berlaku 30 Hari'], icon: Star, popular: false },
  { id: 'sub_2', name: 'Paket Pro', price: 99, credits: 5000, features: ['5.000 Kredit per bulan', 'Dukungan Prioritas', 'Berlaku 30 Hari'], icon: Crown, popular: true },
  { id: 'sub_3', name: 'Paket Ultimate', price: 179, credits: 10000, features: ['10.000 Kredit per bulan', 'Manajer Akun Khusus', 'Berlaku 30 Hari'], icon: ShieldCheck, popular: false }
];

// Paket Topup (Tambahan Kredit)
const TOPUP_PACKAGES = [
  { id: 'tu_1', amount: 500, price: 15, label: 'Lite Reload', icon: Ticket, bonus: null },
  { id: 'tu_2', amount: 1000, price: 28, label: 'Basic Reload', icon: Zap, bonus: '+50 Bonus' },
  { id: 'tu_3', amount: 3000, price: 79, label: 'Pro Reload', icon: Coins, bonus: '+150 Bonus', popular: true },
  { id: 'tu_4', amount: 5000, price: 120, label: 'Enterprise Reload', icon: Database, bonus: '+500 Bonus' }
];

const QRCodeImage = ({ value, size = 200 }) => {
  const qrUrl = `https://quickchart.io/qr?text=${encodeURIComponent(value)}&size=${size}&margin=1`;
  return (
    <div className="bg-white p-4 rounded-3xl shadow-xl border border-slate-100 inline-block">
      <img src={qrUrl} alt="WhatsApp QR" width={size} height={size} className="rounded-xl" />
    </div>
  );
};

/* ============================================================================
   PORTAL ADMIN (UI MOCK)
   ============================================================================ */
const AdminPortal = ({ currentUser, onLogout }) => {
  const [activeTab, setActiveTab] = useState('dashboard');

  return (
    <div className="min-h-screen bg-slate-50 font-sans text-slate-800 flex w-full">
      <aside className="w-64 bg-slate-900 text-slate-300 flex flex-col h-screen fixed left-0 top-0">
        <div className="h-20 flex items-center px-6 border-b border-slate-800 bg-slate-950">
          <div className="flex items-center gap-3">
            <div className="bg-emerald-500 p-2 rounded-xl text-white">
              <ShieldAlert size={20} fill="currentColor" />
            </div>
            <div>
              <h1 className="text-white font-black text-lg leading-tight tracking-tight">AR CONNECT</h1>
              <p className="text-[9px] font-bold text-emerald-500 uppercase tracking-widest">Portal Admin</p>
            </div>
          </div>
        </div>

        <nav className="flex-1 p-4 space-y-2">
          <p className="px-4 text-[10px] font-black uppercase tracking-widest text-slate-500 mb-4 mt-4">Menu Utama</p>
          {[
            { id: 'dashboard', icon: LayoutDashboard, label: 'Dashboard' },
            { id: 'users', icon: Users, label: 'Manajemen Pengguna' },
            { id: 'settings', icon: Settings, label: 'Pengaturan Sistem' },
          ].map((item) => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-bold transition-all text-sm ${
                activeTab === item.id 
                  ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/20' 
                  : 'hover:bg-slate-800 hover:text-white'
              }`}
            >
              <item.icon size={18} />
              {item.label}
            </button>
          ))}
        </nav>

        <div className="p-4 border-t border-slate-800">
          <div className="flex items-center gap-3 px-4 py-3 mb-2 bg-slate-800 rounded-xl">
            <div className="w-8 h-8 rounded-full bg-slate-700 flex items-center justify-center text-white font-bold">AD</div>
            <div className="flex-1 overflow-hidden">
              <p className="text-xs font-bold text-white truncate">{currentUser.nama_syarikat || 'Admin'}</p>
              <p className="text-[10px] text-slate-400 truncate">Administrator Sistem</p>
            </div>
          </div>
          <button onClick={onLogout} className="w-full flex items-center justify-center gap-2 px-4 py-3 text-sm font-bold text-red-400 hover:bg-red-500/10 rounded-xl transition-all">
            <LogOut size={16} /> Keluar
          </button>
        </div>
      </aside>

      <main className="flex-1 ml-64 flex flex-col h-screen overflow-hidden">
        <header className="h-20 bg-white border-b flex items-center justify-between px-8 sticky top-0 z-10">
          <div><h2 className="text-xl font-black text-slate-800 capitalize">{activeTab}</h2></div>
        </header>
        <div className="flex-1 overflow-y-auto p-8 flex items-center justify-center text-slate-400 font-bold">
            Data pengguna nyata akan terhubung selama fase manajemen admin.
        </div>
      </main>
    </div>
  );
};

/* ============================================================================
   PORTAL PENGGUNA (CLIENT) DENGAN INTEGRASI API SEBENARNYA
   ============================================================================ */
const UserPortal = ({ currentUser, token, onLogout }) => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [credits, setCredits] = useState(currentUser.kredit || 0);

  // State WhatsApp
  const [isDeviceLinked, setIsDeviceLinked] = useState(false);
  const [qrStatus, setQrStatus] = useState('idle'); 
  const [qr, setQr] = useState(null);
  const isRequesting = useRef(false);

  // State Blast
  const [isBlasting, setIsBlasting] = useState(false);
  const [blastProgress, setBlastProgress] = useState(0);
  const [messagesSent, setMessagesSent] = useState(0);
  const [messagesFailed, setMessagesFailed] = useState(0);
  const [message, setMessage] = useState('');
  const [targetSource, setTargetSource] = useState('manual');
  const [manualNumbers, setManualNumbers] = useState('');
  const [selectedGroup, setSelectedGroup] = useState('all');
  const [messageFormat, setMessageFormat] = useState('text'); 
  const [delayTime, setDelayTime] = useState(2);

  // State Media
  const [mediaFile, setMediaFile] = useState(null);

  // State Database Kontak
  const [contacts, setContacts] = useState([]);
  const [newContact, setNewContact] = useState({ nama: '', nombor_telefon: '', kumpulan: 'Umum' });
  const [isAddingContact, setIsAddingContact] = useState(false);
  const [isUploadingCSV, setIsUploadingCSV] = useState(false); 
  const [isDeletingAll, setIsDeletingAll] = useState(false);
  const [searchContactQuery, setSearchContactQuery] = useState('');

  // State Pengaturan
  const [pwdData, setPwdData] = useState({ old: '', new: '', confirm: '' });
  const [isUpdatingPwd, setIsUpdatingPwd] = useState(false);

  // State Topup (Voucher)
  const [voucherCode, setVoucherCode] = useState('');

  // State Modal Notifikasi Kustom
  const [notification, setNotification] = useState({ show: false, title: '', message: '', type: 'info' });
  const [blastResultModal, setBlastResultModal] = useState({ isOpen: false, success: 0, failed: 0 });

  const uniqueGroups = useMemo(() => {
    const groups = new Set(contacts.map(c => c.kumpulan));
    return Array.from(groups);
  }, [contacts]);

  const displayedContacts = useMemo(() => {
    if (!searchContactQuery) return contacts;
    const lowerQuery = searchContactQuery.toLowerCase();
    return contacts.filter(contact => 
      contact.nama.toLowerCase().includes(lowerQuery) || 
      contact.nombor_telefon.includes(lowerQuery) ||
      contact.kumpulan.toLowerCase().includes(lowerQuery)
    );
  }, [contacts, searchContactQuery]);

  const showNotification = (title, message, type = 'info') => {
    setNotification({ show: true, title, message, type });
  };

  const fetchContacts = async () => {
    try {
      const res = await fetch(`${API_URL}/contacts/${currentUser.id}`);
      if (res.ok) {
        const data = await res.json();
        setContacts(data);
      }
    } catch (err) {
      console.error("Gagal memuat database", err);
    }
  };

  useEffect(() => {
    fetchContacts();
  }, [activeTab]);

  const handleAddContact = async (e) => {
    e.preventDefault();
    if (!newContact.nombor_telefon) return;

    setIsAddingContact(true);
    try {
      const res = await fetch(`${API_URL}/contacts`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ user_id: currentUser.id, ...newContact })
      });
      if (res.ok) {
        setNewContact({ nama: '', nombor_telefon: '', kumpulan: 'Umum' });
        fetchContacts();
        showNotification("Berhasil", "Kontak baru telah disimpan ke database.", "success");
      }
    } catch (err) {
      console.error(err);
      showNotification("Kesalahan", "Gagal menyimpan kontak.", "error");
    } finally {
      setIsAddingContact(false);
    }
  };

  const handleDeleteContact = async (id) => {
    if (!window.confirm("Apakah Anda yakin ingin menghapus kontak ini?")) return;
    try {
      const res = await fetch(`${API_URL}/contacts/${id}`, { method: 'DELETE' });
      if (res.ok) fetchContacts();
    } catch (err) {
      console.error(err);
    }
  };

  const handleDeleteAllContacts = async () => {
    if (!window.confirm("PERINGATAN! Apakah Anda yakin ingin menghapus SEMUA kontak? Tindakan ini tidak dapat dibatalkan.")) return;

    setIsDeletingAll(true);
    try {
      await Promise.all(contacts.map(contact => 
        fetch(`${API_URL}/contacts/${contact._id}`, { method: 'DELETE' })
      ));

      showNotification("Selesai", "Semua kontak telah berhasil dihapus!", "success");
      fetchContacts();
    } catch (err) {
      console.error("Gagal menghapus semua:", err);
      showNotification("Kesalahan", "Terjadi kesalahan saat menghapus. Silakan coba lagi.", "error");
    } finally {
      setIsDeletingAll(false);
    }
  };

  const handleMediaUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    if (file.size > 16 * 1024 * 1024) {
      showNotification("Berkas Terlalu Besar", "Ukuran berkas media melebihi 16MB. Harap unggah berkas yang lebih kecil.", "warning");
      e.target.value = null;
      return;
    }

    const reader = new FileReader();
    reader.onload = (event) => {
      setMediaFile({
        file: file,
        type: file.type,
        name: file.name,
        base64: event.target.result 
      });
    };
    reader.readAsDataURL(file);
    e.target.value = null; 
  };

  const handleFormatChange = (format) => {
    setMessageFormat(format);
    setMediaFile(null); 
  };

  const handleFileUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setIsUploadingCSV(true);

    try {
      const XLSX = await new Promise((resolve, reject) => {
        if (window.XLSX) return resolve(window.XLSX);
        const script = document.createElement('script');
        script.src = "https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js";
        script.onload = () => resolve(window.XLSX);
        script.onerror = () => reject(new Error('Gagal memuat library XLSX'));
        document.head.appendChild(script);
      });

      const reader = new FileReader();

      reader.onload = async (event) => {
        try {
          const data = new Uint8Array(event.target.result);
          const workbook = XLSX.read(data, { type: 'array' });

          const firstSheetName = workbook.SheetNames[0];
          const worksheet = workbook.Sheets[firstSheetName];

          const rows = XLSX.utils.sheet_to_json(worksheet, { header: 1 });
          const newContacts = [];

          for (let i = 0; i < rows.length; i++) {
            const row = rows[i];
            if (!row || row.length === 0) continue;

            let col0 = row[0] !== undefined ? String(row[0]).trim() : '';
            let col1 = row[1] !== undefined ? String(row[1]).trim() : '';
            let col2 = row[2] !== undefined ? String(row[2]).trim() : '';

            if (col0 && !col1 && col0.includes(',')) {
                const splitCols = col0.split(/[,;\t]/);
                col0 = splitCols[0] ? splitCols[0].replace(/"/g, '').trim() : '';
                col1 = splitCols[1] ? splitCols[1].replace(/"/g, '').trim() : '';
                col2 = splitCols[2] ? splitCols[2].replace(/"/g, '').trim() : '';
            }

            let nama = col0;
            let nombor = col1;
            let kumpulan = col2;

            if (!nombor && nama) {
                const possibleNumber = nama.replace(/[^0-9]/g, '');
                if (possibleNumber.length > 8) {
                    nombor = possibleNumber;
                    nama = 'Pelanggan';
                }
            }

            if (i === 0 && (nama.toLowerCase().includes('name') || nama.toLowerCase().includes('nama') || (nombor && nombor.toLowerCase().includes('number')))) continue;

            const cleanPhone = nombor ? nombor.replace(/[^0-9]/g, '') : '';

            if (!cleanPhone || cleanPhone.length < 8) continue; 

            newContacts.push({
              nama: nama || 'Pelanggan',
              nombor_telefon: cleanPhone,
              kumpulan: kumpulan || 'Impor Excel/CSV'
            });
          }

          if (newContacts.length === 0) {
            showNotification("Format Tidak Valid", "Tidak ada data valid yang ditemukan. Pastikan berkas berisi nomor telepon.", "warning");
            setIsUploadingCSV(false);
            return;
          }

          const res = await fetch(`${API_URL}/contacts/bulk`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ user_id: currentUser.id, contacts: newContacts })
          });

          if (res.ok) {
            showNotification("Impor Berhasil", `${newContacts.length} kontak dari berkas berhasil disimpan ke database!`, "success");
            fetchContacts(); 
          } else {
            showNotification("Kesalahan Server", "Gagal memproses berkas ke database.", "error");
          }
        } catch (err) {
          console.error("Kesalahan memproses berkas", err);
          showNotification("Kesalahan Berkas", "Gagal memproses berkas. Pastikan format (Excel/CSV) benar.", "error");
        } finally {
          setIsUploadingCSV(false);
          if (e.target) e.target.value = null; 
        }
      };

      reader.readAsArrayBuffer(file);

    } catch (err) {
      console.error(err);
      showNotification("Kesalahan Jaringan", "Sistem gagal memuat mesin pemrosesan Excel. Pastikan Anda memiliki akses internet.", "error");
      setIsUploadingCSV(false);
      e.target.value = null;
    }
  };

  const connectWA = async () => {
    setQrStatus('loading');
    setQr(null);
    try {
      const res = await fetch(`${API_URL}/whatsapp/connect/${currentUser.id}`);
      if (!res.ok) throw new Error("Gagal menghubungi server");
    } catch (err) {
      console.error(err);
      setQrStatus('error');
    }
  };

  const logoutWA = async () => {
    setQrStatus('disconnecting');
    try {
      await fetch(`${API_URL}/whatsapp/logout`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ userId: currentUser.id })
      });
    } catch (err) {
      console.error("Gagal memutuskan sambungan dari server:", err);
    }
    setQrStatus('idle');
    setIsDeviceLinked(false);
    setQr(null);
  };

  useEffect(() => {
    let interval;
    let isMounted = true;

    const checkServerStatus = async () => {
      if (isRequesting.current) return; 
      isRequesting.current = true;

      try {
        const res = await fetch(`${API_URL}/whatsapp/connect/${currentUser.id}`);
        const data = await res.json();
        if (!isMounted) return;

        if (data.status === 'connected' || data.connected) {
          setQrStatus('connected');
          setIsDeviceLinked(true);
          setQr(null);
        } else if (data.status === 'disconnected') { 
          setQrStatus('idle');
          setIsDeviceLinked(false);
          setQr(null);
        } else if (data.qr && qrStatus !== 'connected') {
          setQr(prevQr => prevQr !== data.qr ? data.qr : prevQr);
          setQrStatus('qr_ready');
        }
      } catch (err) {
      } finally {
        isRequesting.current = false;
      }
    };

    if (qrStatus === 'loading' || qrStatus === 'qr_ready') {
      interval = setInterval(checkServerStatus, 1500);
    } else if (qrStatus === 'connected') {
      interval = setInterval(checkServerStatus, 5000);
    }

    return () => {
      isMounted = false;
      if (interval) clearInterval(interval);
    };
  }, [qrStatus, currentUser.id]);

  const startBlast = async () => {
    if (!isDeviceLinked) { 
      showNotification("Sesi Tidak Aktif", "Silakan sambungkan WhatsApp Anda (Scan QR) di Dashboard terlebih dahulu.", "warning");
      setActiveTab('dashboard'); 
      return; 
    }

    let numbers = [];

    if (targetSource === 'manual') {
      numbers = manualNumbers.split(/[\n,]+/).map(n => n.trim()).filter(n => n.length > 5);
    } else if (targetSource === 'database') {
      const filteredContacts = selectedGroup === 'all' 
        ? contacts 
        : contacts.filter(c => c.kumpulan === selectedGroup);
      numbers = filteredContacts.map(c => c.nombor_telefon);
    }

    if (numbers.length === 0) {
      showNotification("Tidak Ada Target", "Silakan masukkan atau pilih setidaknya satu nomor target.", "warning");
      return;
    }

    if (messageFormat !== 'text' && !mediaFile) {
        showNotification("Berkas Diperlukan", `Harap unggah berkas ${messageFormat === 'image' ? 'gambar' : 'video'} Anda terlebih dahulu.`, "warning");
        return;
    }

    if (messageFormat === 'text' && !message) {
      showNotification("Pesan Kosong", "Silakan masukkan teks pesan kampanye Anda.", "warning");
      return;
    }

    if (credits < numbers.length) {
      showNotification("Kredit Tidak Cukup", `Anda butuh ${numbers.length} unit kredit untuk kampanye ini. Saldo saat ini: ${credits}.`, "error");
      return;
    }

    setIsBlasting(true); 
    setBlastProgress(0); 
    setMessagesSent(0);
    setMessagesFailed(0);

    let successCount = 0;
    let failCount = 0;

    for (let i = 0; i < numbers.length; i++) {
      try {
        let targetNumber = numbers[i].replace(/[^0-9]/g, ''); 
        if (targetNumber.startsWith('0')) {
            targetNumber = '6' + targetNumber; 
        } else if (targetNumber.startsWith('+')) {
            targetNumber = targetNumber.substring(1);
        }

        const payload = { 
            userId: currentUser.id, 
            to: targetNumber, 
            message: message 
        };

        if (messageFormat !== 'text' && mediaFile) {
            const base64Data = mediaFile.base64.split(',')[1]; 
            payload.media = base64Data;
            payload.mediaType = mediaFile.type;
            payload.fileName = mediaFile.name;
        }

        const res = await fetch(`${API_URL}/whatsapp/send`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(payload)
        });

        if (res.ok) {
          successCount++;
          setMessagesSent(successCount);
          setCredits(prev => prev - 1); 
        } else {
          failCount++;
          setMessagesFailed(failCount);
        }
      } catch (err) {
        failCount++;
        setMessagesFailed(failCount);
      }
      setBlastProgress(Math.floor(((i + 1) / numbers.length) * 100));
      await new Promise(resolve => setTimeout(resolve, delayTime * 1000)); 
    }

    setTimeout(() => {
      setIsBlasting(false);
      setBlastResultModal({
          isOpen: true,
          success: successCount,
          failed: failCount
      });
    }, 1500);
  };

  const handlePurchasePackage = (pkg, type = 'topup') => {
