               <div><h2 className="text-4xl font-black text-slate-900">Paket & Topup Kredit</h2><p className="text-slate-500 font-medium">Pilih paket bulanan atau topup jika kuota habis.</p></div>
               <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                 {SUBSCRIPTION_PACKAGES.map(pkg => <div key={pkg.id} className={`bg-white p-8 rounded-[2.5rem] border-2 flex flex-col ${pkg.popular ? 'border-green-500 shadow-xl' : 'border-slate-100'}`}><h3 className="text-xl font-black mb-4">{pkg.name}</h3><p className="text-4xl font-black mb-6">RM{pkg.price}</p><div className="flex-1 space-y-3 mb-8">{pkg.features.map((f, i) => <p key={i} className="text-sm font-medium flex items-center gap-2"><CheckCircle2 className="text-green-500" size={16}/> {f}</p>)}</div><button onClick={() => handlePurchasePackage(pkg, 'subscription')} className={`w-full py-4 rounded-xl font-black uppercase text-xs ${pkg.popular ? 'bg-green-500 text-white' : 'bg-slate-100 text-slate-600'}`}>Pilih Paket</button></div>)}
               </div>
               <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                  {TOPUP_PACKAGES.map(pkg => <div key={pkg.id} className="bg-white p-6 rounded-[2rem] border shadow-sm"><div className="flex justify-between items-start mb-6"><div className="w-12 h-12 bg-slate-50 rounded-2xl flex items-center justify-center text-slate-500"><pkg.icon size={24} /></div><span className="text-xs font-bold text-slate-400">RM{pkg.price}</span></div><p className="text-2xl font-black mb-1">{pkg.amount.toLocaleString()}</p><p className="text-[10px] font-bold text-slate-400 uppercase mb-4">Kredit</p><button onClick={() => handlePurchasePackage(pkg, 'topup')} className="w-full py-3 bg-slate-900 text-white rounded-xl font-black uppercase text-[10px]">Beli Topup</button></div>)}
               </div>
            </div>
          )}

          {/* Tab Pengaturan */}
          {activeTab === 'settings' && (
            <div className="max-w-4xl mx-auto animate-in fade-in slide-in-from-bottom-4 duration-500 space-y-10">
              <div className="bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden">
                <div className="bg-slate-900 p-10 text-white flex items-center gap-6">
                  <div className="w-20 h-20 bg-green-500 rounded-[2rem] flex items-center justify-center text-3xl font-black uppercase">{currentUser.nama_syarikat?.[0]}</div>
                  <div><h3 className="text-2xl font-black">{currentUser.nama_syarikat}</h3><p className="text-slate-400">{currentUser.email}</p></div>
                </div>
                <div className="p-10 space-y-12">
                  <section>
                    <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6">Profil Perusahaan</h4>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                      <div className="bg-slate-50 p-6 rounded-2xl border">
                        <Building2 size={16} className="text-slate-400 mb-1" />
                        <p className="font-bold text-slate-900">{currentUser.nama_syarikat}</p>
                      </div>
                      <div className="bg-slate-50 p-6 rounded-2xl border">
                        <Mail size={16} className="text-slate-400 mb-1" />
                        <p className="font-bold text-slate-900">{currentUser.email}</p>
                      </div>
                    </div>
                  </section>
                  <section>
                    <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6">Ubah Kata Sandi</h4>
                    <div className="bg-white p-8 rounded-3xl border border-slate-200">
                      <form onSubmit={handleChangePassword} className="space-y-6">
                        <div className="space-y-2">
                          <label className="text-xs font-bold text-slate-500">Kata Sandi Lama</label>
                          <input 
                            type="password" 
                            required 
                            value={pwdData.old} 
                            onChange={e => setPwdData({...pwdData, old: e.target.value})} 
                            className="w-full p-4 bg-slate-50 border rounded-2xl focus:border-green-500 outline-none font-bold text-sm" 
                          />
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                          <div className="space-y-2">
                            <label className="text-xs font-bold text-slate-500">Kata Sandi Baru</label>
                            <input 
                              type="password" 
                              required 
                              value={pwdData.new} 
                              onChange={e => setPwdData({...pwdData, new: e.target.value})} 
                              className="w-full p-4 bg-slate-50 border rounded-2xl focus:border-green-500 outline-none font-bold text-sm" 
                            />
                          </div>
                          <div className="space-y-2">
                            <label className="text-xs font-bold text-slate-500">Konfirmasi Kata Sandi Baru</label>
                            <input 
                              type="password" 
                              required 
                              value={pwdData.confirm} 
                              onChange={e => setPwdData({...pwdData, confirm: e.target.value})} 
                              className="w-full p-4 bg-slate-50 border rounded-2xl focus:border-green-500 outline-none font-bold text-sm" 
                            />
                          </div>
                        </div>
                        <button 
                          disabled={isUpdatingPwd} 
                          type="submit" 
                          className="px-10 py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs hover:bg-green-600 transition-all flex items-center gap-2"
                        >
                          {isUpdatingPwd ? <Loader2 className="animate-spin" /> : <Save size={16} />} Perbarui Kata Sandi
                        </button>
                      </form>
                    </div>
                  </section>
                </div>
              </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

/* ============================================================================
   KOMPONEN UTAMA APLIKASI
   ============================================================================ */
export default function App() {
  const [currentUser, setCurrentUser] = useState(null);
  const [token, setToken] = useState('');
  const [viewMode, setViewMode] = useState('login'); // 'login', 'register', 'forgot'

  const [formData, setFormData] = useState({ email: '', password: '', nama_syarikat: '' });
  const [loading, setLoading] = useState(false);
  const [errorMsg, setErrorMsg] = useState('');
  const [successMsg, setSuccessMsg] = useState('');

  useEffect(() => {
    const savedUser = localStorage.getItem('user');
    const savedToken = localStorage.getItem('token');
    if (savedUser && savedToken) {
      setCurrentUser(JSON.parse(savedUser));
      setToken(savedToken);
    }
  }, []);

  const handleAuth = async (e) => {
    e.preventDefault();
    setLoading(true);
    setErrorMsg('');
    setSuccessMsg('');

    let endpoint = '/auth/login';
    if (viewMode === 'register') endpoint = '/auth/register';
    if (viewMode === 'forgot') endpoint = '/auth/forgot-password';

    const payload = viewMode === 'forgot' 
        ? { email: formData.email }
        : { email: formData.email, kata_laluan: formData.password, nama_syarikat: formData.nama_syarikat };

    try {
      const res = await fetch(`${API_URL}${endpoint}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });
      const data = await res.json();

      if (!res.ok) throw new Error(data.message || 'Terjadi kesalahan sistem.');

      if (viewMode === 'login') {
        localStorage.setItem('token', data.token);
        localStorage.setItem('user', JSON.stringify(data.user));
        setToken(data.token);
        setCurrentUser(data.user);
      } else if (viewMode === 'forgot') {
        setSuccessMsg('Tautan pengaturan ulang kata sandi telah dikirim ke email Anda.');
        setTimeout(() => setViewMode('login'), 3000);
      } else {
        setSuccessMsg('Pendaftaran berhasil! Silakan masuk.');
        setViewMode('login');
      }
    } catch (err) {
      setErrorMsg(err.message);
    } finally {
      setLoading(false);
    }
  };

  const onLogout = () => {
    localStorage.clear();
    setCurrentUser(null);
    setToken('');
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6 font-sans">
        <div className="w-full max-w-md bg-white rounded-[3rem] shadow-2xl p-10 border">
          <div className="text-center mb-10">
            <div className="w-16 h-16 bg-green-500 rounded-2xl flex items-center justify-center mx-auto mb-4 text-white shadow-lg"><Zap size={32} fill="currentColor" /></div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tighter">AR CONNECT</h1>
            <p className="text-slate-400 font-bold text-xs uppercase mt-1">Sistem Blast Terpadu</p>
          </div>

          {viewMode !== 'forgot' && (
            <div className="mb-8 flex justify-center gap-2">
                <button onClick={() => setViewMode('login')} className={`px-4 py-2 rounded-full text-xs font-black transition-all ${viewMode === 'login' ? 'bg-slate-900 text-white' : 'text-slate-400'}`}>Log Masuk</button>
                <button onClick={() => setViewMode('register')} className={`px-4 py-2 rounded-full text-xs font-black transition-all ${viewMode === 'register' ? 'bg-slate-900 text-white' : 'text-slate-400'}`}>Daftar</button>
            </div>
          )}

          {errorMsg && <div className="p-4 rounded-2xl mb-6 text-xs font-bold flex items-center gap-2 bg-red-50 text-red-500 animate-in fade-in"><AlertCircle size={16} /> {errorMsg}</div>}
          {successMsg && <div className="p-4 rounded-2xl mb-6 text-xs font-bold flex items-center gap-2 bg-green-50 text-green-500 animate-in fade-in"><CheckCircle2 size={16} /> {successMsg}</div>}

          <form onSubmit={handleAuth} className="space-y-4">
            {viewMode === 'register' && (
               <div className="space-y-2">
                 <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nama Perusahaan</label>
                 <div className="relative">
                   <Building2 className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
                   <input type="text" onChange={(e) => setFormData({...formData, nama_syarikat: e.target.value})} placeholder="Nama Perusahaan" required className="w-full pl-12 pr-5 py-5 bg-slate-50 rounded-2xl border-2 border-slate-50 focus:border-green-500 font-bold text-sm outline-none transition-all" />
                 </div>
               </div>
            )}
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Alamat Email</label>
              <div className="relative">
                <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
                <input type="email" onChange={(e) => setFormData({...formData, email: e.target.value})} placeholder="email@contoh.com" required className="w-full pl-12 pr-5 py-5 bg-slate-50 rounded-2xl border-2 border-slate-50 focus:border-green-500 font-bold text-sm outline-none transition-all" />
              </div>
            </div>
            {viewMode !== 'forgot' && (
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Kata Sandi</label>
                <div className="relative">
                  <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
                  <input type="password" placeholder="••••••••" onChange={(e) => setFormData({...formData, password: e.target.value})} required className="w-full pl-12 pr-5 py-5 bg-slate-50 rounded-2xl border-2 border-slate-50 focus:border-green-500 font-bold text-sm outline-none transition-all" />
                </div>
              </div>
            )}

            {viewMode === 'login' && (
              <div className="flex justify-end">
                <button type="button" onClick={() => setViewMode('forgot')} className="text-[10px] font-black text-green-600 uppercase tracking-widest hover:underline">Lupa Kata Sandi?</button>
              </div>
            )}

            <button disabled={loading} type="submit" className="w-full py-5 bg-green-500 text-white rounded-2xl font-black hover:bg-green-600 transition-all shadow-xl shadow-green-100 mt-4 uppercase tracking-widest flex justify-center items-center gap-2 hover:scale-[1.02] active:scale-95">
              {loading ? <Loader2 className="animate-spin" /> : 
               (viewMode === 'login' ? <LogIn size={20} /> : viewMode === 'forgot' ? <Send size={20} /> : <PlusCircle size={20} />)} 
              {viewMode === 'login' ? 'Log Masuk' : viewMode === 'forgot' ? 'Kirim Link Reset' : 'Daftar Akun'}
            </button>

            {viewMode === 'forgot' && (
               <button type="button" onClick={() => setViewMode('login')} className="w-full py-3 text-[10px] font-black text-slate-400 uppercase tracking-widest hover:text-slate-600">Kembali ke Log Masuk</button>
            )}
          </form>
          <p className="text-center text-slate-400 text-[10px] font-black uppercase tracking-[0.2em] mt-10">&copy; 2024 AR CONNECT TECHNOLOGY</p>
        </div>
      </div>
    );
  }

  if (currentUser.email === 'admin@arconnect.my') return <AdminPortal currentUser={currentUser} onLogout={onLogout} />;
  return <UserPortal currentUser={currentUser} token={token} onLogout={onLogout} />;
}
